class Solution(object):
    def checkAlmostEquivalent(self, word1, word2):
        from collections import Counter
        freq1 = Counter(word1)
        freq2 = Counter(word2)
        for char in 'abcdefghijklmnopqrstuvwxyz':
            if abs(freq1[char] - freq2[char]) > 3:
                return False
        return True
